sql:
SELECT demographic_id, AVG(covid_test_count) AS average_covid_test_count
FROM covid_tests
GROUP BY demographic_id;

SELECT TS.demographic_id
FROM testing_statistics AS TS
WHERE TS.total_tests > 100 AND TS.total_positive_cases > 50;

SELECT covid_deaths
FROM covid_deaths
WHERE demographic_id = 2 AND death_date = '2020-03-20';

SELECT *
FROM testing_statistics
WHERE total_tests > 10000;

SELECT AVG(average_test_result_time) AS avg_test_result_time
FROM testing_statistics
WHERE demographic_id = 1;

SELECT SUM(covid_count) AS total_positive_cases
FROM covid_cases
WHERE demographic_id = 1;

SELECT demographic_id, SUM(covid_deaths) AS total_deaths
FROM covid_deaths
GROUP BY demographic_id;

SELECT demographic_id, SUM(total_tests) AS total_tests
FROM testing_statistics
GROUP BY demographic_id;

SELECT summary
FROM health_reports
WHERE report_id = 0;

